import { Button } from "@/components/ui/button"
import { Card, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Shield, Users, MapPin, CheckCircle, BarChart3, FileDown } from "lucide-react"
import Link from "next/link"

export default function LandingPage() {
  return (
    <div className="min-h-screen relative overflow-hidden bg-slate-50 selection:bg-[color:var(--senegal-yellow)] selection:text-slate-900">

      {/* Dynamic Background Mesh */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-[color:var(--senegal-green)] rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob" />
        <div className="absolute top-0 right-1/4 w-96 h-96 bg-[color:var(--senegal-yellow)] rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-2000" />
        <div className="absolute -bottom-32 left-1/3 w-96 h-96 bg-[color:var(--senegal-red)] rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-4000" />
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-100 contrast-150 mix-blend-overlay"></div>
      </div>

      <header className="fixed top-4 left-1/2 -translate-x-1/2 z-50 w-[95%] max-w-5xl">
        <div className="glass rounded-full px-6 py-3 flex items-center justify-between shadow-sm hover:shadow-md transition-all duration-300">
          <div className="flex items-center gap-3">
            <span className="text-xl font-bold tracking-tight text-slate-900">
              Contrôle <span className="text-[color:var(--gov-blue)]">TaxiGuard</span>
            </span>
          </div>
          <nav className="flex items-center gap-4">
            <Link href="/auth/login">
              <Button className="rounded-full bg-slate-900 hover:bg-slate-800 text-white px-6 shadow-lg shadow-slate-900/20 transition-transform active:scale-95">
                Connexion
              </Button>
            </Link>
          </nav>
        </div>
      </header>

      {/* Premium Hero Section */}
      <section className="relative z-10 container mx-auto px-4 pt-40 pb-20">
        <div className="max-w-4xl mx-auto text-center space-y-8">
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full glass border border-slate-200/50 shadow-sm text-sm font-medium text-slate-600 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-[color:var(--senegal-green)] opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-[color:var(--senegal-green)]"></span>
            </span>
            Système National de Sécurité Routière
          </div>

          <h1 className="text-6xl md:text-7xl font-extrabold tracking-tight text-slate-900 animate-in fade-in slide-in-from-bottom-8 duration-700 delay-150">
            Modernisation du <br />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-[color:var(--gov-blue)] to-indigo-600">
              Contrôle Routier
            </span>
          </h1>

          <p className="text-xl text-slate-600 max-w-2xl mx-auto leading-relaxed animate-in fade-in slide-in-from-bottom-8 duration-700 delay-300">
            Une plateforme gouvernementale unifiée pour la vérification des taxis,
            la sécurité des citoyens et la gestion intelligente des transports au Sénégal.
          </p>

          <div className="flex gap-4 justify-center pt-4 animate-in fade-in slide-in-from-bottom-8 duration-700 delay-500">
            <Link href="/auth/login">
              <Button size="lg" className="rounded-full h-12 px-8 bg-[color:var(--gov-blue)] hover:bg-[color:var(--gov-blue-dark)] text-white shadow-xl shadow-blue-900/20 text-base font-medium transition-all hover:-translate-y-1">
                Accéder au Portail
              </Button>
            </Link>
            <Button variant="outline" size="lg" className="rounded-full h-12 px-8 border-slate-300 hover:bg-slate-50 text-slate-700 text-base font-medium glass">
              En savoir plus
            </Button>
          </div>
        </div>
      </section>

      {/* Bento Grid Features */}
      <section className="relative z-10 container mx-auto px-4 py-20">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-6xl mx-auto">

          {/* Main Large Card */}
          <div className="md:col-span-2 glass rounded-3xl p-8 border border-white/60 shadow-xl shadow-slate-200/50 relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity">
              <Shield className="w-64 h-64 text-[color:var(--gov-blue)]" />
            </div>
            <div className="relative z-10 h-full flex flex-col justify-between">
              <div>
                <div className="w-12 h-12 rounded-2xl bg-blue-50 flex items-center justify-center mb-6 text-[color:var(--gov-blue)]">
                  <Shield className="w-6 h-6" />
                </div>
                <h3 className="text-2xl font-bold text-slate-900 mb-2">Vérification en Temps Réel</h3>
                <p className="text-slate-600 max-w-md">
                  Accès instantané aux bases de données nationales pour vérifier la validité des permis,
                  des assurances et des licences de transport en moins de 30 secondes.
                </p>
              </div>
              <div className="mt-8">
                <div className="inline-flex items-center gap-2 text-sm font-semibold text-[color:var(--gov-blue)]">
                  Découvrir la technologie <CheckCircle className="w-4 h-4" />
                </div>
              </div>
            </div>
          </div>

          {/* Tall Card */}
          <div className="md:row-span-2 glass rounded-3xl p-8 border border-white/60 shadow-xl shadow-slate-200/50 flex flex-col items-center text-center relative overflow-hidden group">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent to-slate-50/50 opacity-0 group-hover:opacity-100 transition-opacity" />
            <div className="w-16 h-16 rounded-full bg-green-50 flex items-center justify-center mb-6 text-[color:var(--senegal-green)] group-hover:scale-110 transition-transform duration-500">
              <Users className="w-8 h-8" />
            </div>
            <h3 className="text-2xl font-bold text-slate-900 mb-4">Portails Dédiés</h3>
            <div className="space-y-3 w-full text-left mt-4">
              <div className="p-3 rounded-xl bg-white/50 border border-white flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-[color:var(--senegal-green)]" />
                <span className="text-sm font-medium text-slate-700">Agents de Terrain</span>
              </div>
              <div className="p-3 rounded-xl bg-white/50 border border-white flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-[color:var(--gov-blue)]" />
                <span className="text-sm font-medium text-slate-700">Administrateurs</span>
              </div>
              <div className="p-3 rounded-xl bg-white/50 border border-white flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-[color:var(--senegal-yellow)]" />
                <span className="text-sm font-medium text-slate-700">Superviseurs</span>
              </div>
            </div>
          </div>

          {/* Small Card 1 */}
          <div className="glass rounded-3xl p-8 border border-white/60 shadow-xl shadow-slate-200/50 group hover:-translate-y-1 transition-transform">
            <MapPin className="w-10 h-10 text-[color:var(--senegal-red)] mb-4" />
            <h3 className="text-xl font-bold text-slate-900 mb-2">Géolocalisation</h3>
            <p className="text-sm text-slate-600">Suivi précis des points de contrôle et des patrouilles actives.</p>
          </div>

          {/* Small Card 2 */}
          <div className="glass rounded-3xl p-8 border border-white/60 shadow-xl shadow-slate-200/50 group hover:-translate-y-1 transition-transform">
            <BarChart3 className="w-10 h-10 text-[color:var(--senegal-yellow)] mb-4" />
            <h3 className="text-xl font-bold text-slate-900 mb-2">Analytique</h3>
            <p className="text-sm text-slate-600">Tableaux de bord décisionnels pour le ministère.</p>
          </div>

        </div>
      </section>

      {/* Stats Section */}
      <section className="relative z-10 container mx-auto px-4 pb-20">
        <div className="max-w-6xl mx-auto">
          <div className="grid md:grid-cols-3 gap-8">
            {[
              { value: "24/7", label: "Disponibilité Système", color: "text-[color:var(--gov-blue)]" },
              { value: "100%", label: "Sécurité des Données", color: "text-[color:var(--senegal-green)]" },
              { value: "< 1s", label: "Temps de Réponse", color: "text-[color:var(--senegal-red)]" }
            ].map((stat, i) => (
              <div key={i} className="text-center p-8 rounded-3xl hover:bg-white/40 transition-colors duration-300">
                <div className={`text-5xl font-black mb-2 tracking-tighter ${stat.color}`}>{stat.value}</div>
                <div className="text-slate-500 font-medium uppercase tracking-wide text-sm">{stat.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="relative z-10 border-t border-slate-200 bg-white/50 backdrop-blur-sm mt-auto">
        <div className="container mx-auto px-4 py-8 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex gap-2">
            <div className="w-8 h-1 bg-[color:var(--senegal-green)] rounded-full" />
            <div className="w-8 h-1 bg-[color:var(--senegal-yellow)] rounded-full" />
            <div className="w-8 h-1 bg-[color:var(--senegal-red)] rounded-full" />
          </div>
          <p className="text-center md:text-right text-slate-500 text-sm font-medium">
            &copy; 2025 Contrôle TaxiGuard. République du Sénégal.
          </p>
        </div>
      </footer>
    </div>
  )
}
